39	/** Integration test for the eval endpoint over a temporary {@code user.home}. */
40	@MicronautTest
41	@ResourceLock("user.home")
42	class EvalControllerTest {
43	
44	    @Inject
45	    @Client("/")
46	    HttpClient client;
47	
48	    private static final ObjectMapper MAPPER = new ObjectMapper();
49	    private static String originalUserHome;
50	    private static Path tempHome;
51	
52	    @BeforeAll
53	    static void setUpHome() throws IOException {
54	        originalUserHome = System.getProperty("user.home");
55	        tempHome = Files.createTempDirectory("agy-eval-test-home");
56	        System.setProperty("user.home", tempHome.toString());
57	    }
58	
59	    @AfterAll
60	    static void restoreHome() {
61	        if (originalUserHome != null) System.setProperty("user.home", originalUserHome);
62	    }
63	
64	    private void writeAntigravity(String id, String transcript, String summaryJson)
65	        throws IOException {
66	        Path logs = tempHome
67	            .resolve(".gemini")
68	            .resolve("antigravity-cli")
69	            .resolve("brain")
70	            .resolve(id)
71	            .resolve(".system_generated")
72	            .resolve("logs");
73	        Files.createDirectories(logs);
74	        Files.writeString(logs.resolve("transcript.jsonl"), transcript);
75	        if (summaryJson != null) Files.writeString(logs.resolve("summary.json"), summaryJson);
76	    }
77	
78	    private JsonNode get(String uri) throws IOException {
79	        return MAPPER.readTree(client.toBlocking().retrieve(uri));
80	    }
81	
82	    private boolean containsName(JsonNode arr, String name) {
83	        return StreamSupport
84	            .stream(arr.spliterator(), false)
85	            .anyMatch(n -> n.get("name").asText().equals(name));
86	    }
87	
88	    @Test
89	    void scoresCachedAnalysesForASource() throws IOException {
90	        String transcript =
91	            "{\"type\":\"USER_INPUT\",\"content\":\"go\",\"created_at\":\"2026-06-19T10:00:00Z\"}\n";
92	        writeAntigravity(
93	            "s-good",
94	            transcript,
95	            "{\"shortTitle\":\"Fixed build\",\"summary\":\"Updated the JDK and it passed.\"," +
96	            "\"flow\":[\"Read config\"],\"recommendations\":[\"Pin the JDK\"]," +
97	            "\"issues\":[{\"error\":\"Build failed\",\"circumvention\":\"Used JDK 25\"}]}"
98	        );
99	        writeAntigravity("s-poor", transcript, "{\"summary\":\"\"}");
100	        writeAntigravity("s-none", transcript, null);
101	
102	        JsonNode r = get("/api/eval?flavor=antigravity-cli");
103	
104	        assertEquals(3, r.get("sessionCount").asInt());
105	        assertEquals(2, r.get("evaluatedSessions").asInt());
106	        assertTrue(r.get("avgScore").asDouble() > 0.0);
107	        assertTrue(r.get("modelLabel").asText().contains("gemini"));
108	        assertTrue(containsName(r.get("checkPassRates"), "schema-complete"));
109	        // The empty analysis is the lowest-scoring case.
110	        assertEquals("s-poor", r.get("worstCases").get(0).get("sessionId").asText());
111	        // Judge is opt-in: absent by default, with a prompt to run it.
112	        assertFalse(r.get("judge").get("ran").asBoolean());
113	        assertTrue(r.get("judge").get("note").asText().contains("Run the LLM judge"));
114	    }
115	
116	    @Test
117	    void judgeRequestedDegradesWithoutAiKey() throws IOException {
118	        writeAntigravity(
119	            "s-good",
120	            "{\"type\":\"USER_INPUT\",\"content\":\"go\",\"created_at\":\"2026-06-19T10:00:00Z\"}\n",
121	            "{\"shortTitle\":\"t\",\"summary\":\"s\",\"flow\":[\"f\"],\"recommendations\":[\"r\"]}"
122	        );
123	
124	        JsonNode r = get("/api/eval?flavor=antigravity-cli&judge=true");
125	
126	        // No GEMINI_API_KEY in the test environment, so the judge degrades gracefully.
127	        assertFalse(r.get("judge").get("ran").asBoolean());
128	        assertTrue(r.get("judge").get("note").asText().contains("Configure an AI provider"));
129	    }
130	
131	    @Test
132	    void savesAndListsRunHistory() throws IOException {
133	        // Round-trips the persistence path; no seeded sessions needed (and adding a session dir here
134	        // would perturb the exact session counts other tests assert on this shared temp home).
135	        String reportJson = client.toBlocking().retrieve("/api/eval?flavor=antigravity-cli");
136	        String savedJson = client
137	            .toBlocking()
138	            .retrieve(
139	                HttpRequest
140	                    .POST("/api/eval/runs", reportJson)
141	                    .contentType(MediaType.APPLICATION_JSON)
142	            );
143	        JsonNode saved = MAPPER.readTree(savedJson);
144	        assertEquals("antigravity-cli", saved.get("flavor").asText());
145	        assertTrue(saved.has("savedAt"));
146	
147	        JsonNode history = get("/api/eval/runs?flavor=antigravity-cli");
148	        assertTrue(history.isArray());
149	        assertTrue(history.size() >= 1);
150	        assertEquals("antigravity-cli", history.get(0).get("flavor").asText());
151	
152	        // Delete the run we just saved and confirm it is gone.
153	        String savedAt = saved.get("savedAt").asText();
154	        JsonNode del = MAPPER.readTree(
155	            client
156	                .toBlocking()
157	                .retrieve(
158	                    HttpRequest.DELETE(
159	                        "/api/eval/runs?savedAt=" +
160	                        java.net.URLEncoder.encode(savedAt, java.nio.charset.StandardCharsets.UTF_8)
161	                    )
162	                )
163	        );
164	        assertEquals(1, del.get("deleted").asInt());
165	        JsonNode after = get("/api/eval/runs?flavor=antigravity-cli");
166	        assertFalse(
167	            StreamSupport
168	                .stream(after.spliterator(), false)
169	                .anyMatch(n -> savedAt.equals(n.get("savedAt").asText()))
170	        );
171	    }
172	
173	    @Test
