27	import java.util.Optional;
28	import java.util.stream.Stream;
29	
30	/**
31	 * Reads OpenAI Codex CLI sessions from {@code ~/.codex/sessions} and exposes them through the same
32	 * shape {@link BrainController} uses for Antigravity transcripts, so the existing frontend can render
33	 * them. Codex rollout files are converted to the timeline-step schema by {@link CodexAdapter}.
34	 */
35	@Singleton
36	public class CodexSessionReader implements SessionSource {
37	
38	    /** The flavor selector value the frontend sends for Codex sessions. */
39	    public static final String FLAVOR = "codex";
40	
41	    @Override
42	    public boolean handles(String flavor) {
43	        return FLAVOR.equals(flavor);
44	    }
45	
46	    private Path sessionsDir() {
47	        return Paths.get(System.getProperty("user.home"), ".codex", "sessions");
48	    }
49	
50	    /**
51	     * @return one entry per Codex session ({@code id}, {@code summary}, {@code updatedAt}), newest
52	     *     first. Empty when no Codex sessions exist.
53	     */
54	    public List<Map<String, String>> listConversations() {
55	        Path root = sessionsDir();
56	        if (!Files.isDirectory(root)) return List.of();
57	
58	        try (Stream<Path> paths = Files.walk(root)) {
59	            return paths
60	                .filter(p -> p.getFileName().toString().endsWith(".jsonl"))
61	                .filter(Files::isRegularFile)
62	                .map(this::describe)
63	                .filter(info -> info != null)
64	                .sorted((a, b) ->
65	                    Long.compare(
66	                        Long.parseLong(b.get("updatedAt")),
67	                        Long.parseLong(a.get("updatedAt"))
68	                    )
69	                )
70	                .toList();
71	        } catch (IOException e) {
72	            e.printStackTrace();
73	            return List.of();
74	        }
75	    }
76	
77	    // Cap how many lines we scan per file when deriving a title for the list view. The clean user
78	    // prompt is always near the top, so this avoids loading entire (possibly multi-MB) rollouts into
79	    // memory just to populate the sidebar.
80	    private static final int SUMMARY_SCAN_LINES = 256;
81	
82	    private Map<String, String> describe(Path file) {
83	        try {
84	            String id = stripExtension(file.getFileName().toString());
85	            List<String> head;
86	            try (Stream<String> lines = Files.lines(file)) {
87	                head = lines.limit(SUMMARY_SCAN_LINES).toList();
88	            }
89	            String summary = CodexAdapter
90	                .deriveSummary(head)
91	                .orElse("Codex session " + id.substring(0, Math.min(8, id.length())));
92	            long modified = Files.getLastModifiedTime(file).toMillis();
93	
94	            Map<String, String> info = new HashMap<>();
95	            info.put("id", id);
96	            info.put("summary", summary);
97	            info.put("updatedAt", String.valueOf(modified));
98	            return info;
99	        } catch (IOException e) {
100	            return null;
101	        }
102	    }
103	
104	    /**
105	     * @param id the session id (the rollout filename without its {@code .jsonl} extension)
106	     * @return the session's timeline as a JSON array string, or {@code "[]"} if not found
107	     */
108	    public String transcriptJson(String id) throws IOException {
109	        Path file = findById(id);
110	        if (file == null) return "[]";
111	        return CodexAdapter.toTranscriptJson(Files.readAllLines(file));
112	    }
113	
114	    /**
115	     * @return whether a Codex session with this id exists.
116	     */
117	    public boolean sessionExists(String id) throws IOException {
118	        return findById(id) != null;
119	    }
120	
121	    /**
122	     * @return the condensed analysis input for a session (one list of lines per sequence), or empty
123	     *     when the session is not found.
124	     */
125	    public List<List<String>> analysisSequences(String id) throws IOException {
126	        Path file = findById(id);
127	        if (file == null) return List.of();
128	        return CodexAdapter.toAnalysisSequences(Files.readAllLines(file));
129	    }
130	
131	    // Analysis summaries are cached in a tool-owned hidden directory under ~/.codex/sessions so we
132	    // never write alongside (or into) the files Codex itself manages.
133	    private SummaryCache cache() {
134	        return new SummaryCache(sessionsDir().resolve(".agybrainviz"));
135	    }
136	
137	    @Override
138	    public Optional<String> cachedSummary(String id) throws IOException {
139	        return cache().read(id);
140	    }
141	
142	    @Override
143	    public void deleteCache(String id) throws IOException {
144	        cache().delete(id);
145	    }
146	
147	    @Override
148	    public void writeCache(String id, String summaryJson, String title) throws IOException {
149	        cache().write(id, summaryJson, title);
150	    }
151	
152	    // Locate a session by matching its id against actual filenames (never build a path from the id,
153	    // which would allow traversal).
154	    private Path findById(String id) throws IOException {
155	        Path root = sessionsDir();
156	        if (!Files.isDirectory(root)) return null;
